#include <stdio.h>
#include <string.h>
#include <stdint.h>
#include <stdbool.h>

/* ============================================
 * IoT Sensor Data Structures in C
 * Common in embedded systems and microcontrollers
 * ============================================
 */

// Define maximum buffer sizes
#define MAX_READINGS 10
#define DEVICE_ID_LEN 16

// 1. STRUCT for sensor data packet
// Similar to Python class, groups related data
typedef struct {
    uint16_t device_id;
    float temperature;      // Sensor measurement
    float humidity;         // Sensor measurement
    float pressure;         // Sensor measurement
    uint32_t timestamp;     // Unix timestamp
    bool status_ok;         // Actuator/sensor status
} SensorPacket;

// 2. STRUCT for device metadata
typedef struct {
    char device_id[DEVICE_ID_LEN];
    char firmware_version[8];
    char location[32];
    uint8_t sensor_count;
    bool is_active;
} DeviceInfo;

// 3. ARRAY for time-series storage
// Contiguous memory block - efficient for microcontrollers
typedef struct {
    SensorPacket readings[MAX_READINGS];
    uint8_t count;  // Current number of readings
} SensorBuffer;

// Initialize sensor buffer
void init_buffer(SensorBuffer *buffer) {
    buffer->count = 0;
    memset(buffer->readings, 0, sizeof(buffer->readings));
}

// Add reading to buffer (array with index)
bool add_reading(SensorBuffer *buffer, SensorPacket packet) {
    if (buffer->count >= MAX_READINGS) {
        return false;  // Buffer full
    }
    buffer->readings[buffer->count] = packet;
    buffer->count++;
    return true;
}

// 4. QUEUE implementation for FIFO processing
typedef struct {
    SensorPacket queue[MAX_READINGS];
    int front;
    int rear;
    int size;
} SensorQueue;

void init_queue(SensorQueue *q) {
    q->front = -1;
    q->rear = -1;
    q->size = 0;
}

bool is_full(SensorQueue *q) {
    return q->size >= MAX_READINGS;
}

bool is_empty(SensorQueue *q) {
    return q->size == 0;
}

// Enqueue - add to rear (FIFO)
bool enqueue(SensorQueue *q, SensorPacket packet) {
    if (is_full(q)) {
        return false;
    }
    q->rear = (q->rear + 1) % MAX_READINGS;
    q->queue[q->rear] = packet;
    q->size++;
    return true;
}

// Dequeue - remove from front (FIFO)
bool dequeue(SensorQueue *q, SensorPacket *packet) {
    if (is_empty(q)) {
        return false;
    }
    q->front = (q->front + 1) % MAX_READINGS;
    *packet = q->queue[q->front];
    q->size--;
    return true;
}

// 5. JSON-like serialization to string
void serialize_to_json(SensorPacket *p, char *output, size_t max_len) {
    snprintf(output, max_len,
        "{\"device_id\":%d,\"temperature\":%.1f,\"humidity\":%.1f,\"timestamp\":%u}",
        p->device_id, p->temperature, p->humidity, p->timestamp);
}

// Print sensor packet
void print_packet(SensorPacket *p) {
    printf("Device: %u | Temp: %.1f°C | Humidity: %.1f%% | Time: %u | Status: %s\n",
           p->device_id, p->temperature, p->humidity, p->timestamp,
           p->status_ok ? "OK" : "ERROR");
}

// ============================================
// MAIN - Demonstrate all data structures
// ============================================
int main() {
    printf("=== C Data Structures for IoT ===\n\n");

    // 1. Using Structs
    printf("1. STRUCT - Sensor Data Packet:\n");
    SensorPacket packet1 = {
        .device_id = 101,
        .temperature = 25.7,
        .humidity = 48.0,
        .pressure = 1013.2,
        .timestamp = 1698405330,
        .status_ok = true
    };
    print_packet(&packet1);

    // 2. Using Arrays (Sensor Buffer)
    printf("\n2. ARRAY - Time-series buffer:\n");
    SensorBuffer buffer;
    init_buffer(&buffer);

    SensorPacket packet2 = {102, 26.1, 46.5, 1012.8, 1698405331, true};
    SensorPacket packet3 = {101, 25.8, 47.2, 1013.0, 1698405332, true};

    add_reading(&buffer, packet1);
    add_reading(&buffer, packet2);
    add_reading(&buffer, packet3);

    printf("Stored %d readings in buffer\n", buffer.count);
    for (int i = 0; i < buffer.count; i++) {
        print_packet(&buffer.readings[i]);
    }

    // 3. Using Queue (FIFO)
    printf("\n3. QUEUE - FIFO buffer for transmission:\n");
    SensorQueue transmit_queue;
    init_queue(&transmit_queue);

    // Producer: Add readings to queue
    enqueue(&transmit_queue, packet1);
    enqueue(&transmit_queue, packet2);
    printf("Enqueued 2 packets\n");

    // Consumer: Remove readings in FIFO order
    SensorPacket dequeued;
    while (dequeue(&transmit_queue, &dequeued)) {
        char json_output[128];
        serialize_to_json(&dequeued, json_output, sizeof(json_output));
        printf("Dequeued and transmitting: %s\n", json_output);
    }

    // 4. Device Info Struct
    printf("\n4. DEVICE METADATA - Struct with strings:\n");
    DeviceInfo device = {
        .sensor_count = 3,
        .is_active = true
    };
    strncpy(device.device_id, "sensor-node-12", DEVICE_ID_LEN - 1);
    strncpy(device.firmware_version, "v2.1.4", 7);
    strncpy(device.location, "Building-A-3rd-Floor", 31);

    printf("Device: %s, Firmware: %s, Location: %s, Active: %s\n",
           device.device_id, device.firmware_version, device.location,
           device.is_active ? "Yes" : "No");

    printf("\n=== Demo Complete ===\n");
    return 0;
}
